  { title: 'Running Queries', href: '/running-queries', icon: MixIcon },
  { title: 'Database Explorer', href: '/explorer', icon: TableIcon },
  { title: 'Merge Operations', href: '/merges', icon: ShuffleIcon },
  { title: 'Clusters', href: '/clusters', icon: UngroupIcon },
  { title: 'Metrics', href: '/metrics', icon: BarChartIcon },
  {
    title: 'Security',
    href: '/security/sessions',
    icon: ShieldIcon,
    isNew: true,
  },
  {
    title: 'System Logs',
    href: '/logs/text-log',
    icon: ScrollTextIcon,
    isNew: true,
  },
  { title: 'Dashboard', href: '/dashboard', icon: DashboardIcon },
  { title: 'Disks', href: '/disks', icon: HardDriveIcon },
  { title: 'Settings', href: '/settings', icon: UpdateIcon },
  { title: 'ZooKeeper', href: '/zookeeper?path=/', icon: RollerCoasterIcon },
  { title: 'CPU Profiler', href: '/profiler', icon: CpuIcon, isNew: true },
  { title: 'Query Cache', href: '/query-cache', icon: DatabaseZapIcon },
  {
    title: 'Expensive Queries',
    href: '/expensive-queries',
    icon: CircleDollarSignIcon,
  },
  {
    title: 'Dictionaries',
    href: '/dictionaries',
    icon: BookOpenIcon,
    isNew: true,
  },
  {
    title: 'Audit Log',
    href: '/security/audit-log',
    icon: ShieldAlertIcon,
    isNew: true,
  },
] as const

// ============================================================================
// Slim Header
// ============================================================================

function SlimHeader({ hostCount }: { hostCount: number }) {
  return (
    <div className="flex items-center gap-2.5">
      <HomeIcon className="size-5" />
      <h1 className="text-lg font-semibold tracking-tight">
        ClickHouse Monitor
      </h1>
      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
        <div className="size-1.5 rounded-full bg-green-500 animate-pulse" />
        <span>
          {hostCount} host{hostCount !== 1 ? 's' : ''}
        </span>
      </div>
    </div>
  )
}

// ============================================================================
// Compact Navigation Grid
// ============================================================================

function CompactNav() {
  return (
    <div>
      <h2 className="text-sm font-medium text-muted-foreground mb-2">
        Navigation
      </h2>
      <BentoGrid>
        {navItems.map((item) => {
          const Icon = item.icon
          return (
            <BentoItem key={item.href} size="small" interactive>
              <Link
                href={item.href}
                className="flex items-center gap-2 py-0.5 group"
              >
                <Icon className="size-4 shrink-0 text-muted-foreground group-hover:text-foreground transition-colors" />
                <span className="text-sm truncate group-hover:text-foreground transition-colors">
                  {item.title}
                </span>
                {'isNew' in item && item.isNew && (
                  <span className="ml-auto shrink-0 inline-flex items-center px-1.5 py-0.5 rounded-full text-[10px] font-medium bg-blue-500/10 text-blue-500 dark:bg-blue-500/20">
                    New
                  </span>
                )}
              </Link>
            </BentoItem>
          )
        })}
      </BentoGrid>
    </div>
  )
}

// ============================================================================
// Overview Skeleton
// ============================================================================

function OverviewSkeleton() {
  return (
    <BentoGrid>
      {[...Array(6)].map((_, i) => (
        <BentoItem key={i} size={i === 2 ? 'wide' : 'small'}>
          <div className="flex flex-col gap-2 h-full">
            <Skeleton className="h-4 w-24" />
            <Skeleton className="h-16 w-full" />
          </div>
        </BentoItem>
      ))}
    </BentoGrid>
  )
}

// ============================================================================
// Main Content
// ============================================================================

function HomeContent() {
  const { hosts } = useHosts()
  const hostCount = hosts?.length ?? 0

  return (
    <div className="space-y-4 pb-4">
      <SlimHeader hostCount={hostCount} />

      <Suspense fallback={<OverviewSkeleton />}>
        <BentoOverview />
      </Suspense>

      <CompactNav />
    </div>
  )
}

// ============================================================================
// Page
// ============================================================================

export default function HomePage() {
  return (
    <Suspense fallback={<OverviewSkeleton />}>
      <HomeContent />
    </Suspense>
  )
}

